42	
43	const MODEL_PROVIDER_SETTINGS: Array<{
44	  provider: ProviderKind;
45	  title: string;
46	  description: string;
47	  placeholder: string;
48	  example: string;
49	}> = [
50	  {
51	    provider: "codex",
52	    title: "Codex",
53	    description: "Save additional Codex model slugs for the picker and `/model` command.",
54	    placeholder: "your-codex-model-slug",
55	    example: "gpt-6.7-codex-ultra-preview",
56	  },
57	] as const;
58	
59	function getCustomModelsForProvider(
60	  settings: ReturnType<typeof useAppSettings>["settings"],
61	  provider: ProviderKind,
62	) {
63	  switch (provider) {
64	    case "codex":
65	    default:
66	      return settings.customCodexModels;
67	  }
68	}
69	
70	function getDefaultCustomModelsForProvider(
71	  defaults: ReturnType<typeof useAppSettings>["defaults"],
72	  provider: ProviderKind,
73	) {
74	  switch (provider) {
75	    case "codex":
76	    default:
77	      return defaults.customCodexModels;
78	  }
79	}
80	
81	function patchCustomModels(provider: ProviderKind, models: string[]) {
82	  switch (provider) {
83	    case "codex":
84	    default:
85	      return { customCodexModels: models };
86	  }
87	}
88	
89	function SettingsRouteView() {
90	  const { theme, setTheme, resolvedTheme } = useTheme();
91	  const { settings, defaults, updateSettings } = useAppSettings();
92	  const serverConfigQuery = useQuery(serverConfigQueryOptions());
93	  const [isOpeningKeybindings, setIsOpeningKeybindings] = useState(false);
94	  const [openKeybindingsError, setOpenKeybindingsError] = useState<string | null>(null);
95	  const [customModelInputByProvider, setCustomModelInputByProvider] = useState<
96	    Record<ProviderKind, string>
97	  >({
98	    codex: "",
99	  });
100	  const [customModelErrorByProvider, setCustomModelErrorByProvider] = useState<
101	    Partial<Record<ProviderKind, string | null>>
102	  >({});
103	
104	  const codexBinaryPath = settings.codexBinaryPath;
105	  const codexHomePath = settings.codexHomePath;
106	  const codexServiceTier = settings.codexServiceTier;
107	  const keybindingsConfigPath = serverConfigQuery.data?.keybindingsConfigPath ?? null;
108	
109	  const openKeybindingsFile = useCallback(() => {
110	    if (!keybindingsConfigPath) return;
111	    setOpenKeybindingsError(null);
112	    setIsOpeningKeybindings(true);
113	    const api = ensureNativeApi();
114	    void api.shell
115	      .openInEditor(keybindingsConfigPath, preferredTerminalEditor())
116	      .catch((error) => {
117	        setOpenKeybindingsError(
118	          error instanceof Error ? error.message : "Unable to open keybindings file.",
119	        );
120	      })
121	      .finally(() => {
122	        setIsOpeningKeybindings(false);
123	      });
124	  }, [keybindingsConfigPath]);
125	
126	  const addCustomModel = useCallback((provider: ProviderKind) => {
127	    const customModelInput = customModelInputByProvider[provider];
128	    const customModels = getCustomModelsForProvider(settings, provider);
129	    const normalized = normalizeModelSlug(customModelInput, provider);
130	    if (!normalized) {
131	      setCustomModelErrorByProvider((existing) => ({
132	        ...existing,
133	        [provider]: "Enter a model slug.",
134	      }));
135	      return;
136	    }
137	    if (getModelOptions(provider).some((option) => option.slug === normalized)) {
138	      setCustomModelErrorByProvider((existing) => ({
139	        ...existing,
140	        [provider]: "That model is already built in.",
141	      }));
142	      return;
143	    }
144	    if (normalized.length > MAX_CUSTOM_MODEL_LENGTH) {
145	      setCustomModelErrorByProvider((existing) => ({
146	        ...existing,
147	        [provider]: `Model slugs must be ${MAX_CUSTOM_MODEL_LENGTH} characters or less.`,
148	      }));
149	      return;
150	    }
151	    if (customModels.includes(normalized)) {
152	      setCustomModelErrorByProvider((existing) => ({
153	        ...existing,
154	        [provider]: "That custom model is already saved.",
155	      }));
156	      return;
157	    }
158	
159	    updateSettings(patchCustomModels(provider, [...customModels, normalized]));
160	    setCustomModelInputByProvider((existing) => ({
161	      ...existing,
162	      [provider]: "",
163	    }));
164	    setCustomModelErrorByProvider((existing) => ({
165	      ...existing,
166	      [provider]: null,
167	    }));
168	  }, [customModelInputByProvider, settings, updateSettings]);
169	
170	  const removeCustomModel = useCallback(
171	    (provider: ProviderKind, slug: string) => {
172	      const customModels = getCustomModelsForProvider(settings, provider);
173	      updateSettings(patchCustomModels(provider, customModels.filter((model) => model !== slug)));
174	      setCustomModelErrorByProvider((existing) => ({
175	        ...existing,
176	        [provider]: null,
177	      }));
178	    },
179	    [settings, updateSettings],
180	  );
181	
182	  return (
183	    <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground isolate">
184	      <div className="flex min-h-0 min-w-0 flex-1 flex-col bg-background text-foreground">
185	        {isElectron && (
186	          <div className="drag-region flex h-[52px] shrink-0 items-center border-b border-border px-5">
187	            <span className="text-xs font-medium tracking-wide text-muted-foreground/70">
188	              Settings
189	            </span>
190	          </div>
191	        )}
192	
193	        <div className="flex-1 overflow-y-auto p-6">
194	          <div className="mx-auto flex w-full max-w-3xl flex-col gap-6">
195	            <header className="space-y-1">
196	              <h1 className="text-2xl font-semibold tracking-tight text-foreground">Settings</h1>
197	              <p className="text-sm text-muted-foreground">
198	                Configure app-level preferences for this device.
199	              </p>
200	            </header>
201	
202	            <section className="rounded-2xl border border-border bg-card p-5">
203	              <div className="mb-4">
204	                <h2 className="text-sm font-medium text-foreground">Appearance</h2>
205	                <p className="mt-1 text-xs text-muted-foreground">
206	                  Choose how T3 Code handles light and dark mode.
207	                </p>
208	              </div>
209	
210	              <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
211	                {THEME_OPTIONS.map((option) => {
212	                  const selected = theme === option.value;
213	                  return (
214	                    <button
215	                      key={option.value}
216	                      type="button"
217	                      role="radio"
218	                      aria-checked={selected}
219	                      className={`flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
220	                        selected
221	                          ? "border-primary/60 bg-primary/8 text-foreground"
222	                          : "border-border bg-background text-muted-foreground hover:bg-accent"
223	                      }`}
224	                      onClick={() => setTheme(option.value)}
225	                    >
226	                      <span className="flex flex-col">
227	                        <span className="text-sm font-medium">{option.label}</span>
228	                        <span className="text-xs">{option.description}</span>
229	                      </span>
230	                      {selected ? (
231	                        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
232	                          Selected
233	                        </span>
234	                      ) : null}
235	                    </button>
236	                  );
237	                })}
238	              </div>
239	
240	              <p className="mt-4 text-xs text-muted-foreground">
241	                Active theme: <span className="font-medium text-foreground">{resolvedTheme}</span>
242	              </p>
243	            </section>
244	
245	            <section className="rounded-2xl border border-border bg-card p-5">
246	              <div className="mb-4">
247	                <h2 className="text-sm font-medium text-foreground">Codex App Server</h2>
248	                <p className="mt-1 text-xs text-muted-foreground">
249	                  These overrides apply to new sessions and let you use a non-default Codex install.
250	                </p>
251	              </div>
252	
253	              <div className="space-y-4">
254	                <label htmlFor="codex-binary-path" className="block space-y-1">
255	                  <span className="text-xs font-medium text-foreground">Codex binary path</span>
256	                  <Input
257	                    id="codex-binary-path"
258	                    value={codexBinaryPath}
259	                    onChange={(event) => updateSettings({ codexBinaryPath: event.target.value })}
260	                    placeholder="codex"
261	                    spellCheck={false}
262	                  />
263	                  <span className="text-xs text-muted-foreground">
264	                    Leave blank to use <code>codex</code> from your PATH.
265	                  </span>
266	                </label>
267	
268	                <label htmlFor="codex-home-path" className="block space-y-1">
269	                  <span className="text-xs font-medium text-foreground">CODEX_HOME path</span>
270	                  <Input
271	                    id="codex-home-path"
272	                    value={codexHomePath}
273	                    onChange={(event) => updateSettings({ codexHomePath: event.target.value })}
274	                    placeholder="/Users/you/.codex"
275	                    spellCheck={false}
276	                  />
277	                  <span className="text-xs text-muted-foreground">
278	                    Optional custom Codex home/config directory.
279	                  </span>
280	                </label>
281	
282	                <div className="flex items-center justify-between gap-2 text-xs text-muted-foreground">
283	                  <p>
284	                    Binary source:{" "}
285	                    <span className="font-medium text-foreground">{codexBinaryPath || "PATH"}</span>
286	                  </p>
287	                  <Button
288	                    size="xs"
289	                    variant="outline"
290	                    onClick={() =>
291	                      updateSettings({
292	                        codexBinaryPath: defaults.codexBinaryPath,
293	                        codexHomePath: defaults.codexHomePath,
294	                      })
295	                    }
296	                  >
297	                    Reset codex overrides
298	                  </Button>
299	                </div>
300	              </div>
301	            </section>
302	
303	            <section className="rounded-2xl border border-border bg-card p-5">
304	              <div className="mb-4">
305	                <h2 className="text-sm font-medium text-foreground">Models</h2>
306	                <p className="mt-1 text-xs text-muted-foreground">
307	                  Save additional provider model slugs so they appear in the chat model picker and
308	                  `/model` command suggestions.
309	                </p>
310	              </div>
311	
312	              <div className="space-y-5">
313	                <label className="block space-y-1">
314	                  <span className="text-xs font-medium text-foreground">Default service tier</span>
315	                  <Select
316	                    items={APP_SERVICE_TIER_OPTIONS.map((option) => ({
317	                      label: option.label,
318	                      value: option.value,
319	                    }))}
320	                    value={codexServiceTier}
321	                    onValueChange={(value) => {
322	                      if (!value) return;
323	                      updateSettings({ codexServiceTier: value });
324	                    }}
325	                  >
326	                    <SelectTrigger>
327	                      <SelectValue />
328	                    </SelectTrigger>
329	                    <SelectPopup alignItemWithTrigger={false}>
330	                      {APP_SERVICE_TIER_OPTIONS.map((option) => (
331	                        <SelectItem key={option.value} value={option.value}>
332	                          <div className="flex min-w-0 items-center gap-2">
333	                            {option.value === "fast" ? (
334	                              <ZapIcon className="size-3.5 text-amber-500" />
335	                            ) : (
336	                              <span className="size-3.5 shrink-0" aria-hidden="true" />
337	                            )}
338	                            <span className="truncate">{option.label}</span>
339	                          </div>
340	                        </SelectItem>
341	                      ))}
342	                    </SelectPopup>
343	                  </Select>
344	                  <span className="text-xs text-muted-foreground">
345	                    {APP_SERVICE_TIER_OPTIONS.find((option) => option.value === codexServiceTier)
346	                      ?.description ?? "Use Codex defaults without forcing a service tier."}
347	                  </span>
348	                </label>
349	
350	                {MODEL_PROVIDER_SETTINGS.map((providerSettings) => {
351	                  const provider = providerSettings.provider;
352	                  const customModels = getCustomModelsForProvider(settings, provider);
353	                  const customModelInput = customModelInputByProvider[provider];
354	                  const customModelError = customModelErrorByProvider[provider] ?? null;
355	                  return (
356	                    <div
357	                      key={provider}
358	                      className="rounded-xl border border-border bg-background/50 p-4"
359	                    >
360	                      <div className="mb-4">
361	                        <h3 className="text-sm font-medium text-foreground">
362	                          {providerSettings.title}
363	                        </h3>
364	                        <p className="mt-1 text-xs text-muted-foreground">
365	                          {providerSettings.description}
366	                        </p>
367	                      </div>
368	
369	                      <div className="space-y-4">
370	                        <div className="flex flex-col gap-3 sm:flex-row sm:items-start">
371	                          <label
372	                            htmlFor={`custom-model-slug-${provider}`}
373	                            className="block flex-1 space-y-1"
374	                          >
375	                            <span className="text-xs font-medium text-foreground">
376	                              Custom model slug
377	                            </span>
378	                            <Input
379	                              id={`custom-model-slug-${provider}`}
380	                              value={customModelInput}
381	                              onChange={(event) => {
382	                                const value = event.target.value;
383	                                setCustomModelInputByProvider((existing) => ({
384	                                  ...existing,
385	                                  [provider]: value,
386	                                }));
387	                                if (customModelError) {
388	                                  setCustomModelErrorByProvider((existing) => ({
389	                                    ...existing,
390	                                    [provider]: null,
391	                                  }));
392	                                }
393	                              }}
394	                              onKeyDown={(event) => {
395	                                if (event.key !== "Enter") return;
396	                                event.preventDefault();
397	                                addCustomModel(provider);
398	                              }}
399	                              placeholder={providerSettings.placeholder}
400	                              spellCheck={false}
401	                            />
402	                            <span className="text-xs text-muted-foreground">
403	                              Example: <code>{providerSettings.example}</code>
404	                            </span>
405	                          </label>
406	
407	                          <Button
408	                            className="sm:mt-6"
409	                            type="button"
410	                            onClick={() => addCustomModel(provider)}
411	                          >
412	                            Add model
413	                          </Button>
414	                        </div>
415	
416	                        {customModelError ? (
417	                          <p className="text-xs text-destructive">{customModelError}</p>
418	                        ) : null}
419	
420	                        <div className="space-y-2">
421	                          <div className="flex items-center justify-between gap-2 text-xs text-muted-foreground">
422	                            <p>Saved custom models: {customModels.length}</p>
423	                            {customModels.length > 0 ? (
424	                              <Button
425	                                size="xs"
426	                                variant="outline"
427	                                onClick={() =>
428	                                  updateSettings(
429	                                    patchCustomModels(
430	                                      provider,
431	                                      [...getDefaultCustomModelsForProvider(defaults, provider)],
432	                                    ),
433	                                  )
434	                                }
435	                              >
436	                                Reset custom models
437	                              </Button>
438	                            ) : null}
439	                          </div>
440	
441	                          {customModels.length > 0 ? (
442	                            <div className="space-y-2">
443	                              {customModels.map((slug) => (
444	                                <div
445	                                  key={`${provider}:${slug}`}
446	                                  className="flex items-center justify-between gap-3 rounded-lg border border-border bg-background px-3 py-2"
447	                                >
448	                                  <div className="flex min-w-0 flex-1 items-center gap-2">
449	                                    {provider === "codex" && shouldShowFastTierIcon(slug, codexServiceTier) ? (
450	                                      <ZapIcon className="size-3.5 shrink-0 text-amber-500" />
451	                                    ) : null}
452	                                    <code className="min-w-0 flex-1 truncate text-xs text-foreground">
453	                                      {slug}
454	                                    </code>
455	                                  </div>
456	                                  <Button
457	                                    size="xs"
458	                                    variant="ghost"
459	                                    onClick={() => removeCustomModel(provider, slug)}
460	                                  >
461	                                    Remove
462	                                  </Button>
463	                                </div>
464	                              ))}
465	                            </div>
466	                          ) : (
467	                            <div className="rounded-lg border border-dashed border-border bg-background px-3 py-4 text-xs text-muted-foreground">
468	                              No custom models saved yet.
469	                            </div>
470	                          )}
471	                        </div>
472	                      </div>
473	                    </div>
474	                  );
475	                })}
476	              </div>
477	            </section>
478	
479	            <section className="rounded-2xl border border-border bg-card p-5">
480	              <div className="mb-4">
481	                <h2 className="text-sm font-medium text-foreground">Responses</h2>
482	                <p className="mt-1 text-xs text-muted-foreground">
483	                  Control how assistant output is rendered during a turn.
484	                </p>
485	              </div>
486	
487	              <div className="flex items-center justify-between rounded-lg border border-border bg-background px-3 py-2">
488	                <div>
489	                  <p className="text-sm font-medium text-foreground">Stream assistant messages</p>
490	                  <p className="text-xs text-muted-foreground">
491	                    Show token-by-token output while a response is in progress.
492	                  </p>
493	                </div>
494	                <Switch
495	                  checked={settings.enableAssistantStreaming}
496	                  onCheckedChange={(checked) =>
497	                    updateSettings({
498	                      enableAssistantStreaming: Boolean(checked),
499	                    })
500	                  }
501	                  aria-label="Stream assistant messages"
502	                />
503	              </div>
504	
505	              {settings.enableAssistantStreaming !== defaults.enableAssistantStreaming ? (
506	                <div className="mt-3 flex justify-end">
507	                  <Button
508	                    size="xs"
509	                    variant="outline"
510	                    onClick={() =>
511	                      updateSettings({
512	                        enableAssistantStreaming: defaults.enableAssistantStreaming,
513	                      })
514	                    }
515	                  >
516	                    Restore default
517	                  </Button>
518	                </div>
519	              ) : null}
520	            </section>
521	
522	            <section className="rounded-2xl border border-border bg-card p-5">
523	              <div className="mb-4">
