import { useCallback, useEffect, useSyncExternalStore } from "react";
import { BUILT_IN_THEMES, isThemeName, type ThemeColors, type ThemeName } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Migrate legacy "light" / "dark" / "system" values stored before named themes
 * were introduced. "system" has no direct named equivalent so we resolve it based
 * on the current system preference at migration time.
 */
function migrateStoredValue(raw: string | null): ThemeName {
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "system") return getSystemDark() ? "t3-dark" : "t3-light";
  if (isThemeName(raw)) return raw;
  // Default: respect system preference
  return getSystemDark() ? "t3-dark" : "t3-light";
}

function getStored(): ThemeName {
  const raw = localStorage.getItem(STORAGE_KEY);
  const resolved = migrateStoredValue(raw);
  // Silently upgrade legacy values so future reads are clean
  if (raw !== resolved) {
    localStorage.setItem(STORAGE_KEY, resolved);
  }
  return resolved;
}

/** Convert a camelCase key to --kebab-case CSS custom property name */
function toCustomProp(key: string): string {
  return "--theme-" + key.replace(/([A-Z])/g, (c) => "-" + c.toLowerCase());
}

function applyColorTheme(colors: ThemeColors) {
  const el = document.documentElement;
  for (const [key, value] of Object.entries(colors) as Array<[keyof ThemeColors, string]>) {
    el.style.setProperty(toCustomProp(key), value);
  }
}

function applyTheme(themeName: ThemeName, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const def = BUILT_IN_THEMES[themeName];
  const isDark = def.variant === "dark";

  document.documentElement.classList.toggle("dark", isDark);
  applyColorTheme(def.colors);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

type ThemeSnapshot = {
  themeName: ThemeName;
};

function getSnapshot(): ThemeSnapshot {
  const themeName = getStored();
  if (lastSnapshot && lastSnapshot.themeName === themeName) {
    return lastSnapshot;
  }
  lastSnapshot = { themeName };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes (affects migration default only now,
  // but keep the listener so that if the user has a legacy "system" value in
  // another tab we pick it up correctly via storage event)
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => emitChange();
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const themeName = snapshot.themeName;
  const def = BUILT_IN_THEMES[themeName];

  /** Preserved for DiffWorkerPoolProvider and any other consumer */
  const resolvedTheme: "light" | "dark" = def.variant;

  const setTheme = useCallback((next: ThemeName) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(themeName);
  }, [themeName]);

  return { theme: themeName, setTheme, resolvedTheme, themeDefinition: def } as const;
}

