import { type ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

/**
 * ThemeProvider — mounts useTheme so that CSS custom properties are applied
 * on the document root from the very first render. Wrap the entire app tree
 * with this component (see router.ts Wrap).
 *
 * It intentionally renders no DOM nodes; all side-effects happen inside
 * useTheme via useEffect + the module-level applyTheme() call.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  // Calling useTheme here ensures the subscription is active and CSS vars are
  // in sync for the entire subtree. The module-level applyTheme() in useTheme.ts
  // already fires before React hydrates, so there is no flash.
  useTheme();
  return <>{children}</>;
}

