import { BUILT_IN_THEMES, THEME_NAMES, type ThemeName } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

/**
 * A compact grid of theme cards, each showing a color swatch preview and the
 * theme label. Clicking a card sets that theme immediately.
 */
export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-1 gap-3 sm:grid-cols-3" role="radiogroup" aria-label="Theme">
      {THEME_NAMES.map((name: ThemeName) => {
        const def = BUILT_IN_THEMES[name];
        const selected = theme === name;

        return (
          <button
            key={name}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(name)}
            className={[
              "group flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            ].join(" ")}
          >
            {/* Swatch preview */}
            <div
              className="relative h-14 w-full overflow-hidden rounded-lg border border-black/10"
              style={{ background: def.colors.background }}
              aria-hidden="true"
            >
              {/* Sidebar strip */}
              <div
                className="absolute inset-y-0 left-0 w-6"
                style={{ background: def.colors.sidebar }}
              />
              {/* Status bar strip */}
              <div
                className="absolute inset-x-0 bottom-0 h-3"
                style={{ background: def.colors.statusBar }}
              />
              {/* Editor block */}
              <div
                className="absolute right-1 top-1 h-8 w-[calc(100%-28px)] rounded-sm"
                style={{ background: def.colors.editor }}
              />
              {/* Accent dot */}
              <div
                className="absolute right-2 top-2 h-2 w-2 rounded-full"
                style={{ background: def.colors.accent }}
              />
            </div>

            {/* Label row */}
            <div className="flex items-center justify-between gap-1">
              <span className="text-sm font-medium leading-none text-foreground">
                {def.label}
              </span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>

            {/* Color dots row */}
            <div className="flex items-center gap-1.5" aria-hidden="true">
              {(
                [
                  def.colors.background,
                  def.colors.foreground,
                  def.colors.accent,
                  def.colors.sidebar,
                  def.colors.terminal,
                ] as string[]
              ).map((color, i) => (
                <span
                  // oxlint-disable-next-line react/no-array-index-key
                  key={i}
                  className="h-3 w-3 rounded-full border border-black/10"
                  style={{ background: color }}
                />
              ))}
            </div>
          </button>
        );
      })}
    </div>
  );
}

